mapper.update:
update table_view_share
set table_name = #{tableName,jdbcType=VARCHAR},
  table_type = #{tableType,jdbcType=VARCHAR},
  tab_type = #{tabType,jdbcType=VARCHAR}
where id = #{id,jdbcType=INTEGER}

mapper.select:
SELECT COUNT(res.table_name) as totalTableNum,SUM(fieldNum) as totalFieldNum,SUM(rowNum) as totalRowNum FROM ( SELECT ist.table_name,COUNT(1) as fieldNum,ist.TABLE_ROWS as rowNum FROM table_view_share tv LEFT JOIN information_schema.TABLES ist ON tv.table_name = ist.table_name LEFT JOIN information_schema.COLUMNS isc ON ist.table_name = isc.table_name AND ist.TABLE_SCHEMA = isc.TABLE_SCHEMA WHERE ist.TABLE_SCHEMA in ('putuo_base_data','crawler_base')
and ist.TABLE_COMMENT like CONCAT('%',#{tableName},'%')
and tv.table_type = #{tableType,jdbcType=VARCHAR}
and tv.tab_type = #{tabType,jdbcType=VARCHAR}
GROUP BY tv.table_name )res
